// Generate AWS S3 presigned PUT URL (SigV4) using Web Crypto (no require()).
// AWS keys are inlined for MVP — rotate via IAM after setup is verified.
const subtle = globalThis.crypto.subtle;

const AWS_KEY = '{{ $env.AWS_ACCESS_KEY_ID }}';
const AWS_SECRET = '{{ $env.AWS_SECRET_ACCESS_KEY }}';
const REGION = 'us-east-2';
const BUCKET = 'foodservai-menu-photos';
const HOST = `${BUCKET}.s3.${REGION}.amazonaws.com`;
const EXPIRES = 900;
const MAX_BYTES = 10 * 1024 * 1024;
const ALLOWED_MIME = ['image/jpeg', 'image/png', 'image/webp', 'image/gif'];

const enc = new TextEncoder();
const toHex = (buf) => Array.from(new Uint8Array(buf)).map(b => b.toString(16).padStart(2, '0')).join('');
async function sha256Hex(str) {
  return toHex(await subtle.digest('SHA-256', enc.encode(str)));
}
async function hmac(key, data) {
  const k = key instanceof Uint8Array ? key : enc.encode(key);
  const cryptoKey = await subtle.importKey('raw', k, { name: 'HMAC', hash: 'SHA-256' }, false, ['sign']);
  const sig = await subtle.sign('HMAC', cryptoKey, typeof data === 'string' ? enc.encode(data) : data);
  return new Uint8Array(sig);
}

const raw = $input.first().json;
const body = raw.body || raw;
const fileName = String(body.file_name || body.fileName || 'upload.bin').slice(0, 200);
const mimeType = String(body.mime_type || body.mimeType || 'application/octet-stream').toLowerCase();
const sizeBytes = Number(body.size_bytes || body.sizeBytes || 0);

if (!ALLOWED_MIME.includes(mimeType)) {
  return [{ json: { ok: false, error: 'Unsupported mime_type. Allowed: ' + ALLOWED_MIME.join(', ') } }];
}
if (sizeBytes && sizeBytes > MAX_BYTES) {
  return [{ json: { ok: false, error: `File too large: ${sizeBytes} bytes (max ${MAX_BYTES})` } }];
}

const extMatch = fileName.match(/\.([a-zA-Z0-9]{1,8})$/);
const extFromMime = { 'image/jpeg': 'jpg', 'image/png': 'png', 'image/webp': 'webp', 'image/gif': 'gif' }[mimeType];
const ext = (extMatch ? extMatch[1] : extFromMime || 'bin').toLowerCase();

// uuid v4 from getRandomValues (crypto.randomUUID may also be available)
const uuid = (globalThis.crypto.randomUUID && globalThis.crypto.randomUUID()) || (() => {
  const b = new Uint8Array(16); globalThis.crypto.getRandomValues(b);
  b[6] = (b[6] & 0x0f) | 0x40; b[8] = (b[8] & 0x3f) | 0x80;
  const h = toHex(b);
  return `${h.slice(0,8)}-${h.slice(8,12)}-${h.slice(12,16)}-${h.slice(16,20)}-${h.slice(20)}`;
})();
const key = `menu/${uuid}.${ext}`;

const now = new Date();
const amzDate = now.toISOString().replace(/[:-]|\.\d{3}/g, '');
const dateStamp = amzDate.slice(0, 8);
const credential = `${AWS_KEY}/${dateStamp}/${REGION}/s3/aws4_request`;
const canonicalUri = `/${key}`;

const params = {
  'X-Amz-Algorithm': 'AWS4-HMAC-SHA256',
  'X-Amz-Credential': credential,
  'X-Amz-Date': amzDate,
  'X-Amz-Expires': String(EXPIRES),
  'X-Amz-SignedHeaders': 'host'
};
const canonicalQuery = Object.keys(params).sort()
  .map(k => `${encodeURIComponent(k)}=${encodeURIComponent(params[k])}`)
  .join('&');

const canonicalRequest = [
  'PUT', canonicalUri, canonicalQuery,
  `host:${HOST}\n`, 'host', 'UNSIGNED-PAYLOAD'
].join('\n');

const stringToSign = [
  'AWS4-HMAC-SHA256', amzDate,
  `${dateStamp}/${REGION}/s3/aws4_request`,
  await sha256Hex(canonicalRequest)
].join('\n');

const kDate = await hmac('AWS4' + AWS_SECRET, dateStamp);
const kRegion = await hmac(kDate, REGION);
const kService = await hmac(kRegion, 's3');
const kSigning = await hmac(kService, 'aws4_request');
const signature = toHex(await hmac(kSigning, stringToSign));

const upload_url = `https://${HOST}${canonicalUri}?${canonicalQuery}&X-Amz-Signature=${signature}`;
const public_url = `https://${HOST}${canonicalUri}`;

return [{ json: { ok: true, upload_url, public_url, key, expires_in: EXPIRES, mime_type: mimeType } }];
